 1	import React, { FC, MouseEvent, useState } from 'react';
 2	
 3	import { V1PermittedHostDevices } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import SelectToggle from '@kubevirt-utils/components/toggles/SelectToggle';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { isEmpty } from '@kubevirt-utils/utils/utils';
 7	import { FormGroup, GridItem } from '@patternfly/react-core';
 8	import { Select, SelectGroup, SelectOption } from '@patternfly/react-core';
 9	
10	type DeviceNameSelectProps = {
11	  deviceName: string;
12	  index: number;
13	  permittedHostDevices: V1PermittedHostDevices;
14	  setDeviceName: (resourceName: string) => void;
15	};
16	
17	const DeviceNameSelect: FC<DeviceNameSelectProps> = ({
18	  deviceName,
19	  index,
20	  permittedHostDevices,
21	  setDeviceName,
22	}) => {
23	  const { t } = useKubevirtTranslation();
24	  const [isOpen, setIsOpen] = useState<boolean>(false);
25	
26	  const onToggle = () => setIsOpen((prevIsOpen) => !prevIsOpen);
27	  const onSelect = (event: MouseEvent<HTMLSelectElement>, value: string) => {
28	    setDeviceName(value);
29	    setIsOpen(false);
30	  };
31	  return (
32	    <GridItem span={5}>
33	      <FormGroup fieldId="deviceName" isRequired label={!index && t('Device name')}>
34	        <Select
35	          toggle={SelectToggle({
36	            isExpanded: isOpen,
37	            isFullWidth: true,
38	            onClick: onToggle,
39	            selected: deviceName,
40	          })}
41	          id="deviceName"
42	          isOpen={isOpen}
43	          onOpenChange={(open: boolean) => setIsOpen(open)}
44	          onSelect={onSelect}
45	          popperProps={{ appendTo: () => document.getElementById('tab-modal') }}
46	          selected={deviceName}
47	        >
48	          {!isEmpty(permittedHostDevices?.mediatedDevices) && (
49	            <SelectGroup key="mediated" label={t('Mediated devices')}>
50	              {permittedHostDevices?.mediatedDevices?.map(({ resourceName }) => (
51	                <SelectOption key={resourceName} value={resourceName}>
52	                  {resourceName}
53	                </SelectOption>
54	              ))}
55	            </SelectGroup>
56	          )}
57	          {!isEmpty(permittedHostDevices?.pciHostDevices) && (
58	            <SelectGroup key="pciHost" label={t('PCI host devices')}>
59	              {permittedHostDevices?.pciHostDevices?.map(({ resourceName }) => (
60	                <SelectOption key={resourceName} value={resourceName}>
61	                  {resourceName}
62	                </SelectOption>
63	              ))}
64	            </SelectGroup>
65	          )}
66	          {isEmpty(permittedHostDevices?.mediatedDevices) &&
67	            isEmpty(permittedHostDevices?.pciHostDevices) && (
68	              <SelectOption isDisabled key="noDevices">
69	                {t('No host devices exists')}
70	              </SelectOption>
71	            )}
72	        </Select>
73	      </FormGroup>
74	    </GridItem>
75	  );
76	};
77	
78	export default DeviceNameSelect;

